import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import HomePage from "./components/HomePage";
import LoginPage from "./components/loginpage";
import SignupPage from "./components/SignupPage";
import Dashboard from "./components/Dashboard";
import Project from "./components/dashboard/project";
import ActiveCollaborations from "./components/activecollabrations"; // Import your ActiveCollaborations component
import StudyGroup from "./components/dashboard/studygroup"; // Import the StudyGroup component

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/signup" element={<SignupPage />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/project" element={<Project />} />
        <Route path="/collaborations" element={<ActiveCollaborations />} /> {/* New route for active collaborations */}
        <Route path="/studygroup" element={<StudyGroup />} /> {/* New route for StudyGroup */}
      </Routes>
    </Router>
  );
}

export default App;
